awk '
BEGIN {
  months["Jan"]="01"; months["Feb"]="02"; months["Mar"]="03"; months["Apr"]="04";
  months["May"]="05"; months["Jun"]="06"; months["Jul"]="07"; months["Aug"]="08";
  months["Sep"]="09"; months["Oct"]="10"; months["Nov"]="11"; months["Dec"]="12";
}
{
  # Check if line matches internal API pattern
  if ($0 ~ /\/api\/v[0-9]+\/internal\//) {
    # Extract IP address (first field)
    ip = $1;
    # Skip if IP starts with "10."
    if (ip ~ /^10\./) next;
    # Skip health/ready endpoints (extra safety)
    if ($0 ~ /\/health/ || $0 ~ /\/ready/) next;

    # Extract and convert timestamp
    match($0, /\[([0-9]{2})\/([A-Za-z]{3})\/([0-9]{4}):([0-9]{2}):([0-9]{2}):([0-9]{2})/, ts);
    day = ts[1];
    month = months[ts[2]];
    year = ts[3];
    hour = ts[4];
    min = ts[5];
    sec = ts[6];

    # Build ISO 8601 timestamp
    iso_ts = year "-" month "-" day "T" hour":" min ":" sec;

    # Replace timestamp in the line
    sub(/\[[^\]]+\]/, iso_ts);
    print;
  }
}' /var/log/app/access.log > /home/user/internal_hits.log

